#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 1e7+5;
int T,ph[N],p[N/10],cnt;
bool vis[N];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void init(LL up){
    ph[1]=1,vis[1]=1;
    for(LL i=2;i<=up;i++){
        if(!vis[i])p[++cnt]=i,ph[i]=i-1;
        for(int j=1;j<=cnt&&p[j]*i<=up;j++){
            vis[i*p[j]]=1;
            if(i%p[j]==0){ph[i*p[j]]=ph[i]*p[j];break;}
            else ph[i*p[j]]=ph[i]*ph[p[j]];
        }
    }return;
}
LL QP(LL x,LL y,LL mod){
    LL as=1;
    while(y){
        if(y&1)as=as*x%mod;
        x=x*x%mod,y>>=1;
    }return as;
}
LL Sol(LL mod){
    if(mod==1)return 0;
    return QP(2,Sol(ph[mod])+ph[mod],mod);
}
int main(){
    T=read();init(10000000);
    while(T--){
        LL x=read();
        cout<<Sol(x)<<"\n";
    }
    return 0;
}
